/**
 * Adeptra Merchant — Wix MCP Shopping Server.
 *
 * Makes this store's catalog searchable and its cart buildable by an MCP-
 * speaking AI shopping agent. HARD BOUNDARY: this server never processes
 * payment. begin_checkout returns the current cart plus a Wix-hosted
 * checkout URL — the agent/shopper hands off to Wix's own checkout from
 * there to complete payment. See wix.ts's header comment for the explicit
 * list of endpoints this server deliberately never calls.
 */

import "./loadEnv.js"; // MUST be the first import — see loadEnv.ts's header

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
import { assertCatalogV3, searchProducts, getProduct, getCart, addToCart, updateCartItem, removeCartItem, createCheckoutUrl } from "./wix.js";

if (!process.env.WIX_CLIENT_ID || !process.env.WIX_SITE_URL) {
  console.error("Set WIX_CLIENT_ID and WIX_SITE_URL in .env (see .env.example) before starting this server.");
  process.exit(1);
}

const server = new McpServer({ name: "wix-shopping-server", version: "1.0.0" });

function textResult(data: unknown) {
  return { content: [{ type: "text" as const, text: JSON.stringify(data, null, 2) }] };
}

server.registerTool(
  "search_products",
  {
    title: "Search products",
    description: "Search this store's product catalog by keyword.",
    inputSchema: {
      query: z.string().describe("Search text, e.g. product name or keyword"),
      limit: z.number().int().min(1).max(50).optional(),
    },
  },
  async ({ query, limit }) => textResult(await searchProducts(query, limit ?? 10)),
);

server.registerTool(
  "get_product",
  {
    title: "Get product",
    description: "Get full details for one product by its id, including its variants (needed for add_to_cart).",
    inputSchema: { id: z.string().describe("Product id, from search_products output") },
  },
  async ({ id }) => textResult(await getProduct(id)),
);

server.registerTool(
  "add_to_cart",
  {
    title: "Add to cart",
    description:
      "Add a product to the shopping cart. Wix requires a variantId even for products with no real options (they have one default variant) — call get_product first and read it from the product's variantsInfo.variants.",
    inputSchema: {
      productId: z.string().describe("Product id, from search_products/get_product output"),
      variantId: z.string().describe("Variant id, from get_product's variantsInfo.variants"),
      quantity: z.number().int().min(1).default(1),
    },
  },
  async ({ productId, variantId, quantity }) => textResult(await addToCart(productId, variantId, quantity)),
);

server.registerTool(
  "update_cart_item",
  {
    title: "Update cart item",
    description: "Change the quantity of an existing cart line item.",
    inputSchema: {
      lineItemId: z.string().describe("The cart line item's id, from get_cart/add_to_cart output"),
      quantity: z.number().int().min(1),
    },
  },
  async ({ lineItemId, quantity }) => textResult(await updateCartItem(lineItemId, quantity)),
);

server.registerTool(
  "remove_cart_item",
  {
    title: "Remove cart item",
    description: "Remove a line item from the cart.",
    inputSchema: { lineItemId: z.string().describe("The cart line item's id, from get_cart/add_to_cart output") },
  },
  async ({ lineItemId }) => textResult(await removeCartItem(lineItemId)),
);

server.registerTool(
  "get_cart",
  {
    title: "Get cart",
    description: "Get the current cart contents.",
    inputSchema: {},
  },
  async () => textResult(await getCart()),
);

server.registerTool(
  "begin_checkout",
  {
    title: "Begin checkout",
    description:
      "Returns the current cart summary and a Wix-hosted checkout URL. Does NOT process payment — hand off to checkout_url for the shopper to complete their purchase directly with Wix.",
    inputSchema: {},
  },
  async () => {
    const cart = await getCart();
    const checkout_url = await createCheckoutUrl();
    return textResult({
      cart,
      checkout_url,
      note: "Payment is not handled by this server — complete the purchase at checkout_url, on Wix's own hosted checkout page.",
    });
  },
);

async function main() {
  await assertCatalogV3(); // hard-fails with a clear message if this site isn't on Catalog V3 — see wix.ts
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Wix MCP shopping server running (stdio).");
}

main().catch((e) => {
  console.error(`Failed to start: ${(e as Error).message ?? e}`);
  // process.exitCode, not process.exit() — calling exit() immediately after
  // an in-flight fetch (assertCatalogV3, above) can crash Node on some
  // platforms; setting the code and letting the event loop drain naturally
  // avoids that while still exiting non-zero.
  process.exitCode = 1;
});

